import{_ as a,o as e,c as l,a3 as i}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"用户档案管理","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/user-profiles.md","filePath":"user-guide/settings/user-profiles.md","lastUpdated":1781934556000}'),n={name:"user-guide/settings/user-profiles.md"};function s(r,t,d,o,p,h){return e(),l("div",null,[...t[0]||(t[0]=[i(`<h1 id="用户档案管理" tabindex="-1">用户档案管理 <a class="header-anchor" href="#用户档案管理" aria-label="Permalink to &quot;用户档案管理&quot;">​</a></h1><p>用户档案用于描述「你是谁」。在 LLM Chat 中，它会作为用户身份信息参与上下文构建，让不同 Agent 能以更准确的口吻、称呼和偏好与你对话。</p><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><p>你可以从两个位置进入用户档案管理：</p><ul><li>设置 -&gt; 用户档案管理。</li><li>标题栏右侧的用户档案入口 -&gt; 管理用户档案。</li></ul><p>标题栏中选择的档案会作为全局用户档案；某个 Agent 也可以单独关联自己的用户档案。</p><h2 id="新建用户档案" tabindex="-1">新建用户档案 <a class="header-anchor" href="#新建用户档案" aria-label="Permalink to &quot;新建用户档案&quot;">​</a></h2><ol><li>进入「用户档案管理」。</li><li>点击新建按钮。</li><li>填写 ID/名称、显示名称和描述。</li><li>选择头像。</li><li>按需关联世界书和快捷操作。</li><li>保存后，在标题栏或 Agent 编辑器中选择该档案。</li></ol><p>建议先写一个简短稳定的基础档案，再为不同场景创建专用档案。</p><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">字段</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">ID/名称</td><td style="text-align:left;">档案的内部名称，也会用于部分宏替换场景</td></tr><tr><td style="text-align:left;">显示名称</td><td style="text-align:left;">界面中显示的名称；不填时使用 ID/名称</td></tr><tr><td style="text-align:left;">头像</td><td style="text-align:left;">支持上传图像、选择历史头像或使用路径</td></tr><tr><td style="text-align:left;">描述</td><td style="text-align:left;">注入给 AI 的用户身份信息</td></tr><tr><td style="text-align:left;">关联世界书</td><td style="text-align:left;">当前档案生效时附带的世界书</td></tr><tr><td style="text-align:left;">快捷操作</td><td style="text-align:left;">当前档案生效时显示的快捷操作组</td></tr><tr><td style="text-align:left;">消息样式</td><td style="text-align:left;">用户消息是否跟随 Agent，或使用自定义样式</td></tr><tr><td style="text-align:left;">文本替换规则</td><td style="text-align:left;">针对用户消息的正则预处理规则</td></tr></tbody></table><h2 id="如何写好描述" tabindex="-1">如何写好描述 <a class="header-anchor" href="#如何写好描述" aria-label="Permalink to &quot;如何写好描述&quot;">​</a></h2><p>描述不是越长越好。它应该告诉 AI 与当前对话强相关的信息。</p><p>推荐结构：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我是：一句话身份。</span></span>
<span class="line"><span>偏好：喜欢的称呼、语气和回答粒度。</span></span>
<span class="line"><span>禁忌：不希望 AI 做的事。</span></span>
<span class="line"><span>上下文：长期有效的背景信息。</span></span></code></pre></div><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我是一个独立开发者，主要维护桌面端 AI 工具。</span></span>
<span class="line"><span>我喜欢简洁但准确的技术说明，遇到风险请直接指出。</span></span>
<span class="line"><span>默认用中文回答，代码和命令保留英文。</span></span></code></pre></div><h2 id="全局档案与-agent-档案" tabindex="-1">全局档案与 Agent 档案 <a class="header-anchor" href="#全局档案与-agent-档案" aria-label="Permalink to &quot;全局档案与 Agent 档案&quot;">​</a></h2><p>用户档案有两个常见生效来源：</p><ul><li>全局用户档案：通过标题栏选择，适用于大多数会话。</li><li>Agent 关联档案：在 Agent 编辑器中指定，适用于特定角色或场景。</li></ul><p>当 Agent 有自己的用户档案时，系统会优先使用 Agent 配置；否则使用全局档案作为兜底。</p><h2 id="关联世界书" tabindex="-1">关联世界书 <a class="header-anchor" href="#关联世界书" aria-label="Permalink to &quot;关联世界书&quot;">​</a></h2><p>如果某个用户档案需要长期背景设定，可以关联世界书。例如：</p><ul><li>你的项目背景。</li><li>角色扮演中的玩家设定。</li><li>常用术语和人际关系。</li><li>写作世界观中和「用户」相关的设定。</li></ul><p>关联后，当对话触发关键词时，世界书条目会自动注入上下文。</p><h2 id="关联快捷操作" tabindex="-1">关联快捷操作 <a class="header-anchor" href="#关联快捷操作" aria-label="Permalink to &quot;关联快捷操作&quot;">​</a></h2><p>用户档案可以关联快捷操作组。这样当你切换到某个档案时，输入框工具栏会显示对应的常用指令。</p><p>例如：</p><ul><li>开发者档案：代码审查、生成测试、解释报错。</li><li>写作者档案：润色、续写、检查人物口吻。</li><li>学习档案：生成练习题、总结重点、追问概念。</li></ul><h2 id="消息样式与文本替换" tabindex="-1">消息样式与文本替换 <a class="header-anchor" href="#消息样式与文本替换" aria-label="Permalink to &quot;消息样式与文本替换&quot;">​</a></h2><p>如果你希望某个用户档案有专属发言样式，可以把消息样式切为「自定义」，再调整 Markdown 样式。</p><p>文本替换规则适合做轻量预处理，例如：</p><ul><li>自动修正常用错别字。</li><li>把固定简称展开为完整描述。</li><li>为特定口癖或角色表达做格式化。</li></ul><p>正则规则会影响消息进入上下文前的文本，请先用小范围规则测试。</p><h2 id="数据存储与删除" tabindex="-1">数据存储与删除 <a class="header-anchor" href="#数据存储与删除" aria-label="Permalink to &quot;数据存储与删除&quot;">​</a></h2><p>每个用户档案会以独立目录保存，包含 <code>profile.json</code> 和头像等资源。删除档案时，目录会尽量移入系统回收站。</p><p>建议在大量编辑前先导出或备份配置目录，尤其是包含头像和复杂样式的档案。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么-ai-没有体现我的用户档案" tabindex="-1">为什么 AI 没有体现我的用户档案？ <a class="header-anchor" href="#为什么-ai-没有体现我的用户档案" aria-label="Permalink to &quot;为什么 AI 没有体现我的用户档案？&quot;">​</a></h3><p>检查当前标题栏是否选中了该档案，或者当前 Agent 是否绑定了另一个档案。也要确认 Agent 的提示词中保留了用户档案插入位置。</p><h3 id="用户档案会覆盖-agent-人设吗" tabindex="-1">用户档案会覆盖 Agent 人设吗？ <a class="header-anchor" href="#用户档案会覆盖-agent-人设吗" aria-label="Permalink to &quot;用户档案会覆盖 Agent 人设吗？&quot;">​</a></h3><p>不会。用户档案描述的是用户侧身份，Agent 人设描述的是 AI 侧角色。两者会共同进入上下文。</p><h3 id="描述写很长会有问题吗" tabindex="-1">描述写很长会有问题吗？ <a class="header-anchor" href="#描述写很长会有问题吗" aria-label="Permalink to &quot;描述写很长会有问题吗？&quot;">​</a></h3><p>会增加 Token 占用，也可能稀释重点。长期背景建议放到世界书，用户档案只保留稳定而核心的信息。</p><h3 id="删除档案后还能恢复吗" tabindex="-1">删除档案后还能恢复吗？ <a class="header-anchor" href="#删除档案后还能恢复吗" aria-label="Permalink to &quot;删除档案后还能恢复吗？&quot;">​</a></h3><p>如果成功移入系统回收站，可以从回收站恢复。若回收站不可用或被清空，则需要依赖你自己的备份。</p>`,46)])])}const g=a(n,[["render",s]]);export{u as __pageData,g as default};
